import fs from 'node:fs';
import { execFileSync } from 'node:child_process';
import path from 'node:path';
import { parse } from 'yaml';
import { ensureDir, writeJson, writeText } from './files.js';
import { getPackProblemDir, repoRoot } from './paths.js';

function readYamlIfPresent(filePath) {
  if (!fs.existsSync(filePath)) {
    return null;
  }
  return parse(fs.readFileSync(filePath, 'utf8'));
}

function readJsonIfPresent(filePath) {
  if (!fs.existsSync(filePath)) {
    return null;
  }
  try {
    return JSON.parse(fs.readFileSync(filePath, 'utf8'));
  } catch {
    return null;
  }
}

function getProblemPackDir(problem) {
  if (!problem?.cluster) {
    return null;
  }
  return getPackProblemDir(problem.cluster, problem.problemId);
}

export function getProblemTheoremLoopPaths(problem) {
  const packProblemDir = getProblemPackDir(problem);
  if (!packProblemDir) {
    return {
      packProblemDir: null,
      theoremLoopJsonPath: null,
      theoremLoopMarkdownPath: null,
      legacyBridgeJsonPath: null,
      legacyBridgeMarkdownPath: null,
    };
  }

  return {
    packProblemDir,
    theoremLoopJsonPath: path.join(packProblemDir, 'THEOREM_LOOP.json'),
    theoremLoopMarkdownPath: path.join(packProblemDir, 'THEOREM_LOOP.md'),
    legacyBridgeJsonPath: path.join(packProblemDir, 'SEARCH_THEOREM_BRIDGE.json'),
    legacyBridgeMarkdownPath: path.join(packProblemDir, 'SEARCH_THEOREM_BRIDGE.md'),
  };
}

