      rowStartDerivation282?.representativeAlreadyOnWitnessClass
        ? `The row-start derivation is explicit: the boundary representative already lies on the 282 witness class modulo ${witnessSquareModulus}, so the row equation reduces to t ≡ 0 (mod ${rowProgressionAnchor282.rowIndexPeriod}).`
        : null,
      familyMenuResidueBoundary
      && familyMenuResidueBoundary.sameAsFirstFailingRepresentative
      && familyMenuResidueBoundary.firstRepresentativeHasWitness
      && familyMenuResidueBoundary.earlierRepresentativeMatchCount === 0
        ? `The menu-level first-occurrence boundary is isolated: ${familyMenuResidueBoundary.firstRepresentative} is the first family-menu representative in the 282 witness class ${representativeResidueModuloWitness} mod ${witnessSquareModulus}, so no earlier menu row can fail via witness ${witnessSquareModulus} on that same congruence class.`
        : null,
      familyMenuResidueBoundary
      && familyMenuResidueBoundary.firstRepresentativeHasWitness
      && familyMenuResidueBoundary.sameAsFirstFailingRepresentative
        ? `The mechanism falsifier boundary is explicit: a lower representative in residue class ${representativeResidueModuloWitness} mod ${witnessSquareModulus}, a different first 282 witness, or bridge loss of the 137720141 <-> 282 alignment would all break this packet.`
        : null,
      tupleRowLift132
        ? `The 132-row lift is explicit: adding the 132 row forces the tuple-row CRT class from residue ${tupleRowLift132.preAnchorResidueModuloWitness} mod ${witnessSquareModulus} to the boundary residue ${tupleRowLift132.liftedResidueModuloWitness} mod ${witnessSquareModulus} via k ≡ ${tupleRowLift132.liftParameter} (mod ${tupleRow132.squareModulus}).`
        : null,
      tupleRowActivationBoundary?.pre132HasNoTrackedMatch && tupleRowActivationBoundary.activationIsUnique282
        ? `The activation boundary is explicit: before anchor 132 no tuple-row CRT step lands on any tracked failure residue mod ${witnessSquareModulus}, anchor 132 creates the unique tracked 282 match at residue ${tupleRowActivationBoundary.activationResidueModuloWitness}, and anchor 182 preserves that same unique match.`
        : null,
      menuActivationSurvey.rowsWith132TargetActivationCount > 1
        ? `The 132-activation pattern is reusable on the current finite menu: ${menuActivationSurvey.rowsWith132TargetActivationCount} failing witness rows first activate their own failing tracked tail at anchor 132.`
        : null,
      activationLemmaSchema
