function readP848DynamicMarginProof(problem, atomId) {
  const proofPaths = getP848DynamicMarginProofPaths(problem, atomId);
  if (!proofPaths?.jsonPath) {
    return null;
  }
  let proof = readJsonIfPresent(proofPaths.jsonPath);
  let jsonPath = proofPaths.jsonPath;
  if (!proof && proofPaths.directoryPath && fs.existsSync(proofPaths.directoryPath)) {
    const candidateFilenames = fs.readdirSync(proofPaths.directoryPath)
      .filter((filename) => filename.endsWith('.json'));
    for (const filename of candidateFilenames) {
      const candidatePath = path.join(proofPaths.directoryPath, filename);
      const candidateProof = readJsonIfPresent(candidatePath);
      if (candidateProof?.atomId === atomId) {
        proof = candidateProof;
        jsonPath = candidatePath;
        break;
      }
    }
  }
  if (!proof) {
    return null;
  }
  return {
    ...proof,
    proofId: proof.proofId ?? proofPaths.proofId,
    jsonPath,
  };
}

function buildP848SquarefreeCheck(value) {
  const productPlusOne = Number(value);
  const squareDivisorWitnesses = [];
  const checkedSquareRootFloor = Math.floor(Math.sqrt(productPlusOne));
  for (let divisor = 2; divisor <= checkedSquareRootFloor; divisor += 1) {
    const square = divisor * divisor;
    if (productPlusOne % square === 0) {
      squareDivisorWitnesses.push({
        divisor,
        square,
        quotient: productPlusOne / square,
      });
    }
  }

  return {
    productPlusOne,
    checkedSquareRootFloor,
    squareDivisorWitnesses,
    isSquarefree: squareDivisorWitnesses.length === 0,
  };
}

function buildP848SplitKeyForWitness(witness) {
  return `outP2=${witness.outsiderModP2}|out25=${witness.outsiderMod25}|smaller=${witness.smallerSide}`;
}

function getP848SplitAtomWitnessRows(problem, atom) {
  const packProblemDir = getProblemPackDir(problem);
  if (!packProblemDir) {
    return [];
  }
  const artifactName = Number(atom.prime) === 17
    ? 'MATCHING_PATTERN_MINER_P17.json'
    : 'MATCHING_PATTERN_MINER.json';
  const artifact = readJsonIfPresent(path.join(packProblemDir, artifactName));
  return (artifact?.witnesses ?? [])
    .filter((witness) => buildP848SplitKeyForWitness(witness) === atom.splitKey)
    .map((witness) => ({
      N: witness.N,
      outsider: witness.outsider,
      outsiderMod25: witness.outsiderMod25,
      outsiderModP2: witness.outsiderModP2,
      smallerSide: witness.smallerSide,
      side7Count: witness.side7Count,
      side18Count: witness.side18Count,
      requiredMatchingLowerBound: witness.requiredMatchingLowerBound,
      reconstructedMatchingSize: witness.reconstructedMatchingSize,
      matchingSlack: witness.matchingSlack,
    }));
}

function buildP848VertexPresenceCheck(value, witnessRows, splitModulus) {
  const witnessChecks = witnessRows.map((witness) => {
    const squareCheck = buildP848SquarefreeCheck(Number(witness.outsider) * Number(value) + 1);
    const squareDivisorWitnesses = squareCheck.squareDivisorWitnesses.map((squareWitness) => ({
      ...squareWitness,
      stableUnderCurrentSplitModulus: (Number(splitModulus) * Number(value)) % Number(squareWitness.square) === 0,
    }));
    return {
      N: witness.N,
      outsider: witness.outsider,
      productPlusOne: squareCheck.productPlusOne,
      hasAnySquareDivisor: squareDivisorWitnesses.length > 0,
      hasStableSplitWitness: squareDivisorWitnesses.some((squareWitness) => squareWitness.stableUnderCurrentSplitModulus),
      firstSquareDivisorWitness: squareDivisorWitnesses[0] ?? null,
      firstStableSplitWitness: squareDivisorWitnesses.find((squareWitness) => squareWitness.stableUnderCurrentSplitModulus) ?? null,
      squareDivisorWitnesses,
    };
  });
  const allWitnessRowsCompatible = witnessChecks.length > 0
    && witnessChecks.every((check) => check.hasAnySquareDivisor);
  const allWitnessRowsHaveStableSplitWitness = witnessChecks.length > 0
    && witnessChecks.every((check) => check.hasStableSplitWitness);

  return {
    status: allWitnessRowsHaveStableSplitWitness
      ? 'bounded_presence_supported_by_current_split_modulus'
      : allWitnessRowsCompatible
        ? 'needs_sharper_split_or_parametric_presence_witness'
        : 'failed_vertex_not_compatible_in_witness_row',
    allWitnessRowsCompatible,
    allWitnessRowsHaveStableSplitWitness,
    witnessChecks,
  };
}

function buildP848VertexPresenceRefinement(atom, witnessRows, splitModulus, {
  stableVertexPresenceAtomCount,
  unstableVertexPresenceAtoms,
  failedVertexPresenceAtoms,
}) {
  const conditionsByKey = new Map();

  for (const vertex of unstableVertexPresenceAtoms) {
    const witnessChecks = vertex.presenceCheck?.witnessChecks ?? [];
    for (const [witnessIndex, check] of witnessChecks.entries()) {
      const squareWitness = check.firstSquareDivisorWitness;
      if (!squareWitness) {
        continue;
      }

      const square = Number(squareWitness.square);
      const requiredOutsiderResidue = positiveModulo(check.outsider, square);
      const currentSplitResidue = positiveModulo(check.outsider, splitModulus);
      const gcdWithCurrentSplitModulus = gcdInt(splitModulus, square);
      const compatibleWithCurrentSplit = positiveModulo(currentSplitResidue, gcdWithCurrentSplitModulus)
        === positiveModulo(requiredOutsiderResidue, gcdWithCurrentSplitModulus);
      const combinedSplitModulus = (splitModulus / gcdWithCurrentSplitModulus) * square;
      const conditionKey = `${square}:${requiredOutsiderResidue}`;

      if (!conditionsByKey.has(conditionKey)) {
        conditionsByKey.set(conditionKey, {
          conditionId: `square_${square}_outsider_${requiredOutsiderResidue}`,
          refinementKind: 'square_witness_residue_split',
          divisor: Number(squareWitness.divisor),
          square,
          requiredOutsiderResidueModSquare: requiredOutsiderResidue,
          currentSplitCompatibility: {
            currentSplitModulus: splitModulus,
            currentSplitResidueModCurrentSplitModulus: currentSplitResidue,
            gcdWithCurrentSplitModulus,
            compatibleWithCurrentSplit,
            combinedSplitModulus,
          },
          successorSplitKey: `${atom.splitKey}|out${square}=${requiredOutsiderResidue}`,
          successorAtomId: `${atom.atomId}.square_${square}_out_${requiredOutsiderResidue}`,
          witnessRows: [],
          atomIds: [],
          examples: [],
        });
      }

      const condition = conditionsByKey.get(conditionKey);
      if (!condition.atomIds.includes(vertex.atomId)) {
        condition.atomIds.push(vertex.atomId);
      }
      if (!condition.witnessRows.some((row) => row.witnessIndex === witnessIndex)) {
        condition.witnessRows.push({
          witnessIndex,
          N: check.N,
          outsider: check.outsider,
          productPlusOne: check.productPlusOne,
          quotient: squareWitness.quotient,
        });
      }
      if (condition.examples.length < 8) {
        condition.examples.push({
          atomId: vertex.atomId,
          side: vertex.side,
          value: vertex.value,
          productPlusOne: check.productPlusOne,
        });
      }
    }
  }

  const conditions = [...conditionsByKey.values()]
    .map((condition) => ({
      ...condition,
      atomCount: condition.atomIds.length,
      witnessRowCount: condition.witnessRows.length,
    }))
    .sort((left, right) => {
      if (right.atomCount !== left.atomCount) {
        return right.atomCount - left.atomCount;
      }
      if (left.square !== right.square) {
        return left.square - right.square;
      }
      return left.requiredOutsiderResidueModSquare - right.requiredOutsiderResidueModSquare;
    });
  const coveredUnstableAtomIds = new Set(conditions.flatMap((condition) => condition.atomIds));
  const unstableAtomCount = unstableVertexPresenceAtoms.length;

  return {
    status: unstableAtomCount > 0
      ? 'literal_core_requires_sharper_square_witness_split'
      : failedVertexPresenceAtoms.length > 0
        ? 'literal_core_has_failed_vertex_presence_atoms'
        : 'literal_core_stable_under_current_split_modulus',
    deterministicMove: unstableAtomCount > 0
      ? 'emit_successor_atoms_by_square_witness_residue'
      : 'attempt_symbolic_literal_core_persistence',
    splitModulus,
    stableAtomCount: stableVertexPresenceAtomCount,
    unstableAtomCount,
    failedAtomCount: failedVertexPresenceAtoms.length,
    conditionCount: conditions.length,
    coveredUnstableAtomCount: coveredUnstableAtomIds.size,
    uncoveredUnstableAtomCount: Math.max(0, unstableAtomCount - coveredUnstableAtomIds.size),
    dominantConditions: conditions.slice(0, 8).map((condition) => ({
      conditionId: condition.conditionId,
      square: condition.square,
      requiredOutsiderResidueModSquare: condition.requiredOutsiderResidueModSquare,
      atomCount: condition.atomCount,
      successorSplitKey: condition.successorSplitKey,
    })),
    conditions,
    proofBoundary: 'These square-witness residue classes explain the bounded literal vertex-presence instability; each successor split still needs a theorem-facing persistence proof before it can support an all-N claim.',
  };
}

function buildP848EdgeObstructionCertificate(atom, edgeObstructionAtoms) {
  const edgeAtoms = Array.isArray(edgeObstructionAtoms) ? edgeObstructionAtoms : [];
  const squarefreeEdgeAtoms = edgeAtoms.filter((edge) => edge.squarefreeCheck?.isSquarefree === true);
  const nonSquarefreeEdgeAtoms = edgeAtoms.filter((edge) => edge.squarefreeCheck?.isSquarefree !== true);
  const productPlusOneValues = edgeAtoms
    .map((edge) => Number(edge.squarefreeCheck?.productPlusOne))
    .filter((value) => Number.isFinite(value));
  const buildGroups = (groupKeyForEdge, groupSummaryForFirstEdge) => {
    const groupsByKey = new Map();
    for (const edge of edgeAtoms) {
      const key = groupKeyForEdge(edge);
      if (!groupsByKey.has(key)) {
        groupsByKey.set(key, {
          groupKey: key,
          ...groupSummaryForFirstEdge(edge),
          edgeAtomIds: [],
          examples: [],
        });
      }
      const group = groupsByKey.get(key);
      group.edgeAtomIds.push(edge.atomId);
      if (group.examples.length < 6) {
        group.examples.push({
          atomId: edge.atomId,
          leftValue: edge.pair?.leftValue ?? null,
          rightValue: edge.pair?.rightValue ?? null,
          productPlusOne: edge.squarefreeCheck?.productPlusOne ?? null,
        });
      }
    }
    return [...groupsByKey.values()]
      .map((group) => ({
        ...group,
        edgeCount: group.edgeAtomIds.length,
      }))
      .sort((left, right) => {
        if (right.edgeCount !== left.edgeCount) {
          return right.edgeCount - left.edgeCount;
        }
        return String(left.groupKey).localeCompare(String(right.groupKey));
      });
  };
  const mod25Classes = buildGroups(
    (edge) => `${edge.pair?.leftMod25 ?? 'unknown'}:${edge.pair?.rightMod25 ?? 'unknown'}`,
    (edge) => ({
      leftMod25: edge.pair?.leftMod25 ?? null,
      rightMod25: edge.pair?.rightMod25 ?? null,
    }),
  );
  const primeResidueClasses = buildGroups(
    (edge) => {
      const leftModP = Number(edge.pair?.leftModP);
      const rightModP = Number(edge.pair?.rightModP);
      const productPlusOneModP = Number.isFinite(leftModP) && Number.isFinite(rightModP)
        ? positiveModulo((leftModP * rightModP) + 1, atom.prime)
        : 'unknown';
      return `${edge.pair?.leftModP ?? 'unknown'}:${edge.pair?.rightModP ?? 'unknown'}:${productPlusOneModP}`;
    },
    (edge) => {
      const leftModP = Number(edge.pair?.leftModP);
      const rightModP = Number(edge.pair?.rightModP);
      return {
        leftModP: edge.pair?.leftModP ?? null,
        rightModP: edge.pair?.rightModP ?? null,
        productPlusOneModP: Number.isFinite(leftModP) && Number.isFinite(rightModP)
          ? positiveModulo((leftModP * rightModP) + 1, atom.prime)
          : null,
      };
    },
  );
  const primeSquareFingerprints = buildGroups(
    (edge) => [
      edge.pair?.leftModP2 ?? 'unknown',
      edge.pair?.rightModP2 ?? 'unknown',
      edge.pair?.productPlusOneModP2 ?? 'unknown',
    ].join(':'),
    (edge) => ({
      leftModP2: edge.pair?.leftModP2 ?? null,
      rightModP2: edge.pair?.rightModP2 ?? null,
      productPlusOneModP2: edge.pair?.productPlusOneModP2 ?? null,
    }),
  );

  return {
    schema: 'erdos.p848_edge_obstruction_certificate/1',
    certificateId: `${atom.atomId}.edge_obstruction_certificate`,
    status: edgeAtoms.length > 0 && nonSquarefreeEdgeAtoms.length === 0
      ? 'literal_edge_obstruction_certificate_verified'
      : 'literal_edge_obstruction_certificate_needs_recheck',
    proofKind: 'literal_product_plus_one_squarefree_missing_edge_certificate',
    edgeAtomCount: edgeAtoms.length,
    squarefreeEdgeAtomCount: squarefreeEdgeAtoms.length,
    nonSquarefreeEdgeAtomCount: nonSquarefreeEdgeAtoms.length,
    allSquarefree: edgeAtoms.length > 0 && nonSquarefreeEdgeAtoms.length === 0,
    productPlusOneRange: productPlusOneValues.length > 0
      ? {
        min: Math.min(...productPlusOneValues),
        max: Math.max(...productPlusOneValues),
      }
      : null,
    residueSummary: {
      mod25ClassCount: mod25Classes.length,
      primeResidueClassCount: primeResidueClasses.length,
      primeSquareFingerprintCount: primeSquareFingerprints.length,
    },
    mod25Classes,
    primeResidueClasses,
    firstPrimeSquareFingerprints: primeSquareFingerprints.slice(0, 16),
    firstEdgeCertificates: edgeAtoms.slice(0, 10).map((edge) => ({
      atomId: edge.atomId,
      leftValue: edge.pair?.leftValue ?? null,
      rightValue: edge.pair?.rightValue ?? null,
      productPlusOne: edge.squarefreeCheck?.productPlusOne ?? null,
      checkedSquareRootFloor: edge.squarefreeCheck?.checkedSquareRootFloor ?? null,
      squareDivisorWitnesses: edge.squarefreeCheck?.squareDivisorWitnesses ?? [],
      isSquarefree: edge.squarefreeCheck?.isSquarefree === true,
    })),
    failedEdgeAtoms: nonSquarefreeEdgeAtoms.slice(0, 10).map((edge) => ({
      atomId: edge.atomId,
      leftValue: edge.pair?.leftValue ?? null,
      rightValue: edge.pair?.rightValue ?? null,
      productPlusOne: edge.squarefreeCheck?.productPlusOne ?? null,
      squareDivisorWitnesses: edge.squarefreeCheck?.squareDivisorWitnesses ?? [],
    })),
    proofBoundary: 'This certifies only the exported literal edge-obstruction atoms for the current split packet. If a later proof replaces literal vertices with moving vertex families, this certificate must be lifted into a symbolic residue-family obstruction proof before it can support an all-N claim.',
    nextTheoremAction: 'Promote this literal edge-obstruction certificate into A5 congruence-persistence families, or emit a sharper successor atom for any edge whose obstruction is not implied by the split hypotheses.',
  };
}

function buildP848EdgeCongruencePersistence(atom, edgeObstructionAtoms, edgeObstructionCertificate, witnessRows) {
  const edgeAtoms = Array.isArray(edgeObstructionAtoms) ? edgeObstructionAtoms : [];
  const verifiedLiteralCertificate = edgeObstructionCertificate?.status
    === 'literal_edge_obstruction_certificate_verified';
  const checks = edgeAtoms.map((edge) => {
    const leftValue = Number(edge.pair?.leftValue);
    const rightValue = Number(edge.pair?.rightValue);
    const productPlusOne = Number(edge.squarefreeCheck?.productPlusOne);
    return {
      atomId: edge.atomId,
      pairIndex: edge.pairIndex,
      leftValue: edge.pair?.leftValue ?? null,
      rightValue: edge.pair?.rightValue ?? null,
      productPlusOne: edge.squarefreeCheck?.productPlusOne ?? null,
      productPlusOneRecomputed: Number.isFinite(leftValue) && Number.isFinite(rightValue)
        ? (leftValue * rightValue) + 1
        : null,
      productPlusOneConstantMatchesCertificate:
        Number.isFinite(leftValue)
        && Number.isFinite(rightValue)
        && Number.isFinite(productPlusOne)
        && ((leftValue * rightValue) + 1) === productPlusOne,
      squarefreeCertificateVerified: edge.squarefreeCheck?.isSquarefree === true,
      dependsOnSampledN: false,
      dependsOnWitnessOutsider: false,
      impliedBySplitHypotheses: true,
      proofReason: 'The exported pair uses literal constants, so left*right+1 is invariant across every row in the split; the squarefree certificate therefore persists without an additional sampled-N congruence.',
    };
  });
  const failedChecks = checks.filter((check) => (
    !check.productPlusOneConstantMatchesCertificate || !check.squarefreeCertificateVerified
  ));
  const proofFamilies = [
    {
      familyId: `${atom.atomId}.edge_constant_squarefree_family`,
      status: verifiedLiteralCertificate && failedChecks.length === 0
        ? 'congruence_persistence_family_verified'
        : 'congruence_persistence_family_needs_recheck',
      proofKind: 'constant_pair_squarefree_invariant',
      edgeAtomCount: checks.length,
      verifiedEdgeAtomCount: checks.length - failedChecks.length,
      failedEdgeAtomCount: failedChecks.length,
      splitKey: atom.splitKey,
      splitModulus: Number(atom.prime) * Number(atom.prime) * 25,
      statement: 'For each exported literal cross pair (l,r), l and r are constants in the packet, so l*r+1 is the same integer for every row satisfying the split hypotheses.',
      proofSteps: [
        'Recompute c = l*r + 1 from the exported literal pair.',
        'Check c matches the squarefree certificate attached to the edge atom.',
        'Because c has no N or outsider variable, the edge obstruction persists over all rows covered by this literal packet.',
      ],
      proofBoundary: 'This is not yet a parameterized edge-family theorem. If later proof work replaces literal pair constants with formulas in N, this constant-family proof must be lifted or replaced.',
      exampleEdgeAtoms: checks.slice(0, 8).map((check) => ({
        atomId: check.atomId,
        leftValue: check.leftValue,
        rightValue: check.rightValue,
        productPlusOne: check.productPlusOne,
      })),
    },
  ];

  return {
    schema: 'erdos.p848_edge_congruence_persistence/1',
    persistenceId: `${atom.atomId}.edge_congruence_persistence`,
    status: verifiedLiteralCertificate && failedChecks.length === 0
      ? 'literal_constant_edge_persistence_verified'
      : 'literal_constant_edge_persistence_needs_recheck',
    proofKind: 'constant_pair_squarefree_invariant',
    splitKey: atom.splitKey,
    splitModulus: Number(atom.prime) * Number(atom.prime) * 25,
    witnessRowCount: Array.isArray(witnessRows) ? witnessRows.length : 0,
    edgeAtomCount: checks.length,
    verifiedEdgeAtomCount: checks.length - failedChecks.length,
    failedEdgeAtomCount: failedChecks.length,
    dependsOnSampledN: false,
    dependsOnWitnessOutsider: false,
    proofFamilies,
    checks,
    failedChecks,
    proofBoundary: 'This verifies A5 congruence persistence only for the exported literal matching core. It does not prove that future parameterized vertex families preserve the same squarefree edge obstructions.',
    nextTheoremAction: 'After this A5 literal persistence pass, promote matching disjointness and the K-envelope, or lift the edge proof if vertex formulas become parameterized.',
  };
}

function buildP848MatchingKEnvelopeCertificate(atom, matchingDisjointness, kEnvelope) {
  const commonCoreCount = Number(kEnvelope?.commonMatchingPairCount);
  const maxRequiredMatchingLowerBound = Number(kEnvelope?.maxRequiredMatchingLowerBound);
  const boundedSlackAgainstMaxK = Number(kEnvelope?.boundedSlackAgainstMaxK);
  const matchingVerified = matchingDisjointness?.status === 'bounded_disjointness_certified'
    && Number(matchingDisjointness.leftVertexCount) === Number(matchingDisjointness.pairCount)
    && Number(matchingDisjointness.rightVertexCount) === Number(matchingDisjointness.pairCount)
    && (matchingDisjointness.reusedLeftValues ?? []).length === 0
    && (matchingDisjointness.reusedRightValues ?? []).length === 0;
  const kEnvelopeVerified = kEnvelope?.status === 'bounded_core_meets_sampled_K_envelope'
    && Number.isFinite(commonCoreCount)
    && Number.isFinite(maxRequiredMatchingLowerBound)
    && Number.isFinite(boundedSlackAgainstMaxK)
    && commonCoreCount >= maxRequiredMatchingLowerBound
    && boundedSlackAgainstMaxK >= 0;

  return {
    schema: 'erdos.p848_matching_k_envelope_certificate/1',
    certificateId: `${atom.atomId}.matching_k_envelope_certificate`,
    status: matchingVerified && kEnvelopeVerified
      ? 'literal_matching_sampled_k_envelope_verified'
      : 'literal_matching_sampled_k_envelope_needs_recheck',
    proofKind: 'literal_disjoint_matching_plus_sampled_k_envelope',
    matchingProof: {
      status: matchingVerified
        ? 'literal_matching_disjointness_verified'
        : 'literal_matching_disjointness_needs_recheck',
      pairCount: matchingDisjointness?.pairCount ?? null,
      leftVertexCount: matchingDisjointness?.leftVertexCount ?? null,
      rightVertexCount: matchingDisjointness?.rightVertexCount ?? null,
      reusedLeftValues: matchingDisjointness?.reusedLeftValues ?? [],
      reusedRightValues: matchingDisjointness?.reusedRightValues ?? [],
      proofSteps: [
        'Count the exported literal left vertices.',
        'Count the exported literal right vertices.',
        'Verify no left value and no right value is reused across the exported pair list.',
      ],
      proofBoundary: 'This proves disjointness for the exported literal pair list. If later work parameterizes vertices, disjointness must be rechecked for the parameterized formulas.',
    },
    kEnvelopeProof: {
      status: kEnvelopeVerified
        ? 'sampled_k_envelope_dominated_by_literal_core'
        : 'sampled_k_envelope_needs_recheck',
      requiredMatchingLowerBoundRange: kEnvelope?.requiredMatchingLowerBoundRange ?? null,
      commonMatchingPairCount: kEnvelope?.commonMatchingPairCount ?? null,
      maxRequiredMatchingLowerBound: kEnvelope?.maxRequiredMatchingLowerBound ?? null,
      boundedSlackAgainstMaxK: kEnvelope?.boundedSlackAgainstMaxK ?? null,
      inequality: Number.isFinite(commonCoreCount) && Number.isFinite(maxRequiredMatchingLowerBound)
        ? `${commonCoreCount} >= ${maxRequiredMatchingLowerBound}`
        : null,
      proofSteps: [
        'Use the exported common-core pair count as the literal matching size.',
        'Compare it against the maximum required matching lower bound recorded by the packet.',
        'Record the slack and keep the all-N K-formula handoff explicit.',
      ],
      proofBoundary: 'This certifies the K-envelope recorded by the current split packet. It is not by itself a universal K(N,x) formula proof for every future row.',
    },
    allLowerLiteralAtomsReady: matchingVerified && kEnvelopeVerified,
    proofBoundary: 'A6/A7 are certified for this literal packet. Split discharge still needs the vertex-successor proofs, edge persistence, and row-universe coverage to be assembled without bounded-only overclaim.',
    nextTheoremAction: 'Assemble this with the verified vertex-successor and edge-persistence layers into a split-discharge readiness certificate, or emit the first missing lower atom.',
  };
}

function buildP848SplitDischargeReadiness(packet, successorPackets) {
  const relevantSuccessors = (successorPackets ?? [])
    .filter((successor) => successor.parentAtomId === packet.atomId);
  const vertexConditionCount = Number(packet.vertexPresenceRefinement?.conditionCount ?? 0);
  const verifiedVertexSuccessorCount = relevantSuccessors
    .filter((successor) => successor.symbolicVertexFamilyLemma?.status === 'symbolic_vertex_family_lemma_verified').length;
  const allVertexSuccessorsVerified = vertexConditionCount > 0
    && verifiedVertexSuccessorCount === vertexConditionCount;
  const lowerLayerChecks = [
    {
      layerId: 'A3_vertex_presence_successors',
      status: allVertexSuccessorsVerified
        ? 'verified'
        : vertexConditionCount === 0
          ? 'not_required'
          : 'blocked',
      evidence: `${verifiedVertexSuccessorCount}/${vertexConditionCount} successor vertex-family lemmas verified`,
    },
    {
      layerId: 'A4_edge_obstruction_certificate',
      status: packet.edgeObstructionCertificate?.status === 'literal_edge_obstruction_certificate_verified'
        ? 'verified'
        : 'blocked',
      evidence: packet.edgeObstructionCertificate?.status ?? null,
    },
    {
      layerId: 'A5_edge_congruence_persistence',
      status: packet.edgeCongruencePersistence?.status === 'literal_constant_edge_persistence_verified'
        ? 'verified'
        : 'blocked',
      evidence: packet.edgeCongruencePersistence?.status ?? null,
    },
    {
      layerId: 'A6_matching_disjointness',
      status: packet.matchingKEnvelopeCertificate?.matchingProof?.status === 'literal_matching_disjointness_verified'
        ? 'verified'
        : 'blocked',
      evidence: packet.matchingKEnvelopeCertificate?.matchingProof?.status ?? null,
    },
    {
      layerId: 'A7_sampled_k_envelope',
      status: packet.matchingKEnvelopeCertificate?.kEnvelopeProof?.status === 'sampled_k_envelope_dominated_by_literal_core'
        ? 'verified_sampled_envelope'
        : 'blocked',
      evidence: packet.matchingKEnvelopeCertificate?.kEnvelopeProof?.inequality ?? null,
    },
  ];
  const blockingChecks = lowerLayerChecks.filter((check) => check.status === 'blocked');
  const readyForSplitLemmaCandidate = blockingChecks.length === 0;

  return {
    schema: 'erdos.p848_split_discharge_readiness/1',
    readinessId: `${packet.atomId}.split_discharge_readiness`,
    status: readyForSplitLemmaCandidate
      ? 'split_discharge_readiness_candidate'
      : 'split_discharge_readiness_blocked',
    proofKind: 'lower_atom_assembly_with_explicit_all_n_handoff',
    atomId: packet.atomId,
    splitKey: packet.splitKey,
    parentObligationId: packet.parentObligationId,
    targetObligationId: packet.targetObligationId,
    lowerLayerChecks,
    blockingChecks,
    theoremCandidate: {
      status: readyForSplitLemmaCandidate
        ? 'candidate_with_open_all_n_handoff_gaps'
        : 'blocked_by_lower_atom',
      statement: `For split ${packet.splitKey}, the exported literal core supplies a disjoint matching of size ${packet.matchingCore?.commonMatchingPairCount ?? '(unknown)'} against the packet K-envelope ${JSON.stringify(packet.kEnvelope?.requiredMatchingLowerBoundRange ?? null)}.`,
      lowerAtomSummary: {
        vertexSuccessorConditionCount: vertexConditionCount,
        verifiedVertexSuccessorCount,
        edgePersistenceStatus: packet.edgeCongruencePersistence?.status ?? null,
        matchingKEnvelopeStatus: packet.matchingKEnvelopeCertificate?.status ?? null,
      },
    },
    openAllNHandoffGaps: [
      {
        gapId: 'row_universe_split_coverage',
        status: 'open',
        note: 'Prove every future threatening row in the parent lane is covered by an emitted and discharged split profile.',
      },
      {
        gapId: 'universal_k_formula_lift',
        status: 'open',
        note: 'Replace the sampled packet K-envelope with the symbolic K(N,x) inequality used by the all-N D2/D3 lane.',
      },
      {
        gapId: 'literal_to_parameterized_vertex_guard',
        status: 'open_if_vertices_move',
        note: 'If later rows require moving vertex formulas instead of literal constants, re-run vertex, edge, and disjointness checks on the parameterized families.',
      },
    ],
    proofBoundary: 'This is readiness for a theorem-facing split lemma candidate, not a final all-N proof. The listed all-N handoff gaps must stay visible until discharged by the row-universe and symbolic K-formula lanes.',
    nextTheoremAction: readyForSplitLemmaCandidate
      ? 'Attack the next p13 split profile or begin the row-universe/symbolic-K handoff once every p13 split has this readiness certificate.'
      : 'Discharge the first blocked lower atom before promoting this split.',
  };
}

function buildP848SplitAtomPacket(problem, plan, atom) {
  const paths = getP848SplitAtomPacketPaths(problem, atom.atomId);
  const commonMatchingPairs = Array.isArray(atom.commonMatchingPairs) ? atom.commonMatchingPairs : [];
  const witnessRows = getP848SplitAtomWitnessRows(problem, atom);
  const splitModulus = Number(atom.prime) * Number(atom.prime) * 25;
  const uniqueLeftValues = [...new Set(commonMatchingPairs.map((pair) => pair.leftValue))].sort((left, right) => left - right);
  const uniqueRightValues = [...new Set(commonMatchingPairs.map((pair) => pair.rightValue))].sort((left, right) => left - right);
  const maxRequiredK = Array.isArray(atom.requiredMatchingLowerBoundRange)
    ? Number(atom.requiredMatchingLowerBoundRange[1])
    : null;
  const commonPairCount = Number(atom.commonMatchingPairCount ?? commonMatchingPairs.length);
  const kEnvelopeSlack = Number.isFinite(maxRequiredK) && Number.isFinite(commonPairCount)
    ? commonPairCount - maxRequiredK
    : null;
  const vertexResidues = (value) => ({
    value,
    mod25: positiveModulo(value, 25),
    modP: positiveModulo(value, atom.prime),
    modP2: positiveModulo(value, atom.prime * atom.prime),
  });
  const vertexPresenceAtoms = [
    ...uniqueLeftValues.map((value, index) => {
      const presenceCheck = buildP848VertexPresenceCheck(value, witnessRows, splitModulus);
      return {
        atomId: `${atom.atomId}.V${index + 1}.left_${value}`,
        side: 'side7',
        value,
        residues: vertexResidues(value),
        status: presenceCheck.status,
        presenceCheck,
        goal: `Prove left core vertex ${value} is present in the side7 compatible set for every row in split ${atom.splitKey}.`,
      };
    }),
    ...uniqueRightValues.map((value, index) => {
      const presenceCheck = buildP848VertexPresenceCheck(value, witnessRows, splitModulus);
      return {
        atomId: `${atom.atomId}.V${uniqueLeftValues.length + index + 1}.right_${value}`,
        side: 'side18',
        value,
        residues: vertexResidues(value),
        status: presenceCheck.status,
        presenceCheck,
        goal: `Prove right core vertex ${value} is present in the side18 compatible set for every row in split ${atom.splitKey}.`,
      };
    }),
  ];
  const stableVertexPresenceAtomCount = vertexPresenceAtoms
    .filter((vertex) => vertex.presenceCheck?.allWitnessRowsHaveStableSplitWitness).length;
  const unstableVertexPresenceAtoms = vertexPresenceAtoms
    .filter((vertex) => vertex.presenceCheck?.allWitnessRowsCompatible && !vertex.presenceCheck?.allWitnessRowsHaveStableSplitWitness);
  const failedVertexPresenceAtoms = vertexPresenceAtoms
    .filter((vertex) => vertex.presenceCheck?.allWitnessRowsCompatible === false);
  const vertexPresenceRefinement = buildP848VertexPresenceRefinement(atom, witnessRows, splitModulus, {
    stableVertexPresenceAtomCount,
    unstableVertexPresenceAtoms,
    failedVertexPresenceAtoms,
  });
  const seenLeft = new Set();
  const seenRight = new Set();
  const reusedLeftValues = [];
  const reusedRightValues = [];
  for (const pair of commonMatchingPairs) {
    if (seenLeft.has(pair.leftValue) && !reusedLeftValues.includes(pair.leftValue)) {
      reusedLeftValues.push(pair.leftValue);
    }
    if (seenRight.has(pair.rightValue) && !reusedRightValues.includes(pair.rightValue)) {
      reusedRightValues.push(pair.rightValue);
    }
    seenLeft.add(pair.leftValue);
    seenRight.add(pair.rightValue);
  }

  const edgeObstructionAtoms = commonMatchingPairs.map((pair, index) => {
    const squarefreeCheck = buildP848SquarefreeCheck(Number(pair.leftValue) * Number(pair.rightValue) + 1);
    return {
      atomId: `${atom.atomId}.E${index + 1}.left_${pair.leftValue}_right_${pair.rightValue}`,
      pairIndex: index,
      pair,
      status: squarefreeCheck.isSquarefree
        ? 'bounded_missing_cross_edge_certified_by_squarefree_product_plus_one'
        : 'needs_missing_cross_edge_recheck_non_squarefree_product_plus_one',
      squarefreeCheck,
      goal: `Normalize why (${pair.leftValue}, ${pair.rightValue}) remains a missing cross edge throughout split ${atom.splitKey}.`,
    };
  });

  const allEdgeObstructionsSquarefree = edgeObstructionAtoms.every((edge) => edge.squarefreeCheck.isSquarefree);
  const edgeObstructionCertificate = buildP848EdgeObstructionCertificate(atom, edgeObstructionAtoms);
  const edgeCongruencePersistence = buildP848EdgeCongruencePersistence(
    atom,
    edgeObstructionAtoms,
    edgeObstructionCertificate,
    witnessRows,
  );
  const matchingDisjointness = {
    status: reusedLeftValues.length === 0 && reusedRightValues.length === 0 ? 'bounded_disjointness_certified' : 'failed_reused_vertex',
    leftVertexCount: uniqueLeftValues.length,
    rightVertexCount: uniqueRightValues.length,
    pairCount: commonMatchingPairs.length,
    reusedLeftValues,
    reusedRightValues,
    completionRule: 'A symbolic packet may promote only if the parameterized left and right vertex families remain pairwise disjoint.',
  };
  const kEnvelope = {
    requiredMatchingLowerBoundRange: atom.requiredMatchingLowerBoundRange,
    commonMatchingPairCount: commonPairCount,
    maxRequiredMatchingLowerBound: maxRequiredK,
    minMatchingSlack: atom.minMatchingSlack,
    boundedSlackAgainstMaxK: kEnvelopeSlack,
    status: Number.isFinite(kEnvelopeSlack) && kEnvelopeSlack >= 0
      ? 'bounded_core_meets_sampled_K_envelope'
      : 'blocked_core_below_sampled_K_envelope',
  };
  const matchingKEnvelopeCertificate = buildP848MatchingKEnvelopeCertificate(
    atom,
    matchingDisjointness,
    kEnvelope,
  );

  return {
    schema: 'erdos.p848_split_atom_packet/1',
    generatedAt: new Date().toISOString(),
    problemId: '848',
    packetId: paths?.packetId ?? `p848_split_atom_packet_${sanitizeP848PacketFileStem(atom.atomId)}`,
    atomId: atom.atomId,
    sourcePlanId: plan.planId,
    parentObligationId: atom.parentObligationId,
    targetObligationId: plan.scope?.targetObligationId ?? null,
    prime: atom.prime,
    splitKey: atom.splitKey,
    priority: atom.priority,
    status: 'ready_for_symbolic_persistence_work',
    sourceArtifacts: {
      taskList: 'TASK_LIST.json',
      formalizationWork: 'FORMALIZATION_WORK.json',
      matchingPatternMiner: atom.prime === 17 ? 'MATCHING_PATTERN_MINER_P17.json' : 'MATCHING_PATTERN_MINER.json',
    },
    inputs: {
      witnessCount: atom.witnessCount,
      nRange: atom.nRange,
      boundedTarget: atom.boundedTarget ?? null,
      goal: atom.goal,
      falsifierBoundary: atom.falsifierBoundary,
      witnessRows,
      splitModulus,
    },
    kEnvelope,
    matchingCore: {
      commonMatchingPairExportComplete: atom.commonMatchingPairExportComplete,
      commonMatchingPairCount: commonPairCount,
      commonMatchingPairs,
    },
    vertexPresenceAtoms,
    vertexPresenceSummary: {
      splitModulus,
      witnessRowCount: witnessRows.length,
      vertexPresenceAtomCount: vertexPresenceAtoms.length,
      stableUnderCurrentSplitModulusCount: stableVertexPresenceAtomCount,
      needsSharperSplitOrParametricWitnessCount: unstableVertexPresenceAtoms.length,
      failedVertexPresenceAtomCount: failedVertexPresenceAtoms.length,
      refinementStatus: vertexPresenceRefinement.status,
      refinementConditionCount: vertexPresenceRefinement.conditionCount,
      dominantRefinementConditions: vertexPresenceRefinement.dominantConditions,
      firstUnstableAtoms: unstableVertexPresenceAtoms.slice(0, 8).map((vertex) => ({
        atomId: vertex.atomId,
        side: vertex.side,
        value: vertex.value,
        firstSquareDivisorWitness: vertex.presenceCheck?.witnessChecks?.[0]?.firstSquareDivisorWitness ?? null,
      })),
    },
    vertexPresenceRefinement,
    edgeObstructionAtoms,
    edgeObstructionCertificate,
    edgeCongruencePersistence,
    matchingDisjointness,
    matchingKEnvelopeCertificate,
    summary: {
      vertexPresenceAtomCount: vertexPresenceAtoms.length,
      edgeObstructionAtomCount: edgeObstructionAtoms.length,
      stableVertexPresenceAtomCount,
      unstableVertexPresenceAtomCount: unstableVertexPresenceAtoms.length,
      failedVertexPresenceAtomCount: failedVertexPresenceAtoms.length,
      allEdgeObstructionsSquarefree,
      edgeObstructionCertificateStatus: edgeObstructionCertificate.status,
      edgeCongruencePersistenceStatus: edgeCongruencePersistence.status,
      matchingDisjointnessStatus: matchingDisjointness.status,
      matchingKEnvelopeCertificateStatus: matchingKEnvelopeCertificate.status,
      readyForFirstTheoremPass: atom.commonMatchingPairExportComplete === true
        && matchingDisjointness.status === 'bounded_disjointness_certified'
        && Number.isFinite(kEnvelopeSlack)
        && kEnvelopeSlack >= 0,
    },
    nextTheoremActions: [
      'Promote the literal vertex-presence checks into residue-family vertex formulas if the vertices move with N.',
      unstableVertexPresenceAtoms.length > 0
        ? 'The current split modulus does not stabilize every vertex compatibility witness; either sharpen the split by the missing square-witness residues or replace literal vertices with parameterized families.'
        : 'The current split modulus stabilizes the bounded vertex compatibility witnesses; attempt symbolic persistence before adding a sharper split.',
      'Group edge obstruction atoms by residue pattern and product-plus-one squarefree check before attempting a symbolic persistence proof.',
      'Attack the packet until it either becomes a split lemma or emits a sharper sub-split key.',
    ],
  };
}

function buildP848SplitAtomSuccessorPacket(problem, parentPacket, condition, rank) {
  const paths = getP848SplitAtomSuccessorPacketPaths(problem, parentPacket.atomId, condition.conditionId);
  const affectedAtomIdSet = new Set(condition.atomIds ?? []);
  const vertexResidueModSquare = gcdInt(condition.requiredOutsiderResidueModSquare, condition.square) === 1
    ? positiveModulo(-Number(modularInverseBigInt(condition.requiredOutsiderResidueModSquare, condition.square)), condition.square)
    : null;
  const affectedVertexPresenceAtoms = (parentPacket.vertexPresenceAtoms ?? [])
    .filter((vertex) => affectedAtomIdSet.has(vertex.atomId))
    .map((vertex) => {
      const relevantWitnessChecks = (vertex.presenceCheck?.witnessChecks ?? [])
        .filter((check) => {
          const squareWitness = check.firstSquareDivisorWitness;
          return Number(squareWitness?.square) === Number(condition.square)
            && positiveModulo(check.outsider, condition.square) === condition.requiredOutsiderResidueModSquare;
        });
      const successorChecks = relevantWitnessChecks.map((check) => ({
        N: check.N,
        outsider: check.outsider,
        productPlusOne: check.productPlusOne,
        firstSquareDivisorWitness: check.firstSquareDivisorWitness,
        requiredOutsiderResidueModSquare: condition.requiredOutsiderResidueModSquare,
        witnessOutsiderResidueModSquare: positiveModulo(check.outsider, condition.square),
        witnessSatisfiesSuccessorResidue: positiveModulo(check.outsider, condition.square)
          === condition.requiredOutsiderResidueModSquare,
        stableUnderSuccessorSplitModulus:
          (Number(condition.currentSplitCompatibility.combinedSplitModulus) * Number(vertex.value))
            % Number(condition.square) === 0,
      }));

      return {
        atomId: vertex.atomId,
        side: vertex.side,
        value: vertex.value,
        residues: vertex.residues,
        residueModSquare: positiveModulo(vertex.value, condition.square),
        successorChecks,
        status: successorChecks.length > 0
          && successorChecks.every((check) => check.witnessSatisfiesSuccessorResidue && check.stableUnderSuccessorSplitModulus)
          ? 'bounded_presence_stabilized_by_successor_square_residue'
          : 'needs_successor_presence_recheck',
      };
    });
  const stabilizedAtomCount = affectedVertexPresenceAtoms
    .filter((vertex) => vertex.status === 'bounded_presence_stabilized_by_successor_square_residue').length;
  const failedAtomCount = affectedVertexPresenceAtoms.length - stabilizedAtomCount;
  const symbolicFamilyChecks = affectedVertexPresenceAtoms.map((vertex) => ({
    atomId: vertex.atomId,
    value: vertex.value,
    residueModSquare: vertex.residueModSquare,
    expectedVertexResidueModSquare: vertexResidueModSquare,
    vertexMatchesResidueFamily: vertexResidueModSquare !== null && vertex.residueModSquare === vertexResidueModSquare,
    productPlusOneResidueModSquare: vertexResidueModSquare === null
      ? null
      : positiveModulo(
        (condition.requiredOutsiderResidueModSquare * vertexResidueModSquare) + 1,
        condition.square,
      ),
  }));
  const allAtomsMatchSymbolicFamily = symbolicFamilyChecks.length > 0
    && symbolicFamilyChecks.every((check) => (
      check.vertexMatchesResidueFamily && check.productPlusOneResidueModSquare === 0
    ));
  const symbolicVertexFamilyLemma = {
    lemmaId: `${condition.conditionId}_vertex_family`,
    status: allAtomsMatchSymbolicFamily
      ? 'symbolic_vertex_family_lemma_verified'
      : vertexResidueModSquare === null
        ? 'blocked_non_unit_outsider_residue'
        : 'needs_symbolic_vertex_family_recheck',
    statement: vertexResidueModSquare === null
      ? `The outsider residue ${condition.requiredOutsiderResidueModSquare} is not a unit modulo ${condition.square}; use a non-unit divisibility split instead of inverse-residue normalization.`
      : `If outsider ≡ ${condition.requiredOutsiderResidueModSquare} (mod ${condition.square}) and vertex ≡ ${vertexResidueModSquare} (mod ${condition.square}), then outsider * vertex + 1 ≡ 0 (mod ${condition.square}).`,
    outsiderResidueModSquare: condition.requiredOutsiderResidueModSquare,
    vertexResidueModSquare,
    square: condition.square,
    affectedAtomCount: affectedVertexPresenceAtoms.length,
    verifiedAtomCount: symbolicFamilyChecks.filter((check) => (
      check.vertexMatchesResidueFamily && check.productPlusOneResidueModSquare === 0
    )).length,
    failedAtomCount: symbolicFamilyChecks.filter((check) => (
      !check.vertexMatchesResidueFamily || check.productPlusOneResidueModSquare !== 0
    )).length,
    checks: symbolicFamilyChecks,
    proofBoundary: 'This proves the square-residue vertex-presence family for this successor condition only; sibling conditions still need their own family lemmas.',
  };

  return {
    schema: 'erdos.p848_split_atom_successor_packet/1',
    generatedAt: new Date().toISOString(),
    problemId: '848',
    packetId: paths?.packetId ?? `p848_split_atom_successor_packet_${sanitizeP848PacketFileStem(condition.successorAtomId)}`,
    parentPacketId: parentPacket.packetId,
    parentAtomId: parentPacket.atomId,
    successorAtomId: condition.successorAtomId,
    successorRank: rank,
    conditionId: condition.conditionId,
    priority: rank === 1 ? 'highest_refinement_successor' : 'dominant_refinement_successor',
    status: failedAtomCount === 0
      ? 'candidate_successor_obligation_verified'
      : 'candidate_successor_obligation_needs_recheck',
    splitRefinement: {
      parentSplitKey: parentPacket.splitKey,
      successorSplitKey: condition.successorSplitKey,
      parentSplitModulus: condition.currentSplitCompatibility.currentSplitModulus,
      successorSplitModulus: condition.currentSplitCompatibility.combinedSplitModulus,
      square: condition.square,
      divisor: condition.divisor,
      requiredOutsiderResidueModSquare: condition.requiredOutsiderResidueModSquare,
      compatibleWithCurrentSplit: condition.currentSplitCompatibility.compatibleWithCurrentSplit,
    },
    symbolicVertexFamilyLemma,
    theoremObligation: {
      kind: 'square_residue_vertex_presence_subobligation',
      parentObligationId: parentPacket.parentObligationId,
      targetObligationId: parentPacket.targetObligationId,
      statement: `Under ${condition.successorSplitKey}, stabilize the ${condition.atomCount} literal vertex-presence atoms whose first square witness is ${condition.square}.`,
      proofBoundary: 'This successor packet stabilizes one vertex-presence subfamily only; it is not a full split lemma until the sibling refinement conditions and matching/edge obligations are promoted too.',
    },
    affectedVertexPresenceAtoms,
    checks: {
      affectedAtomCount: affectedVertexPresenceAtoms.length,
      stabilizedAtomCount,
      failedAtomCount,
      allAffectedAtomsPresent: affectedVertexPresenceAtoms.length === condition.atomCount,
      allAffectedAtomsStabilized: failedAtomCount === 0,
      witnessRowCount: condition.witnessRowCount,
      witnessRows: condition.witnessRows,
    },
    nextTheoremActions: [
      'Promote this square-residue successor into a symbolic vertex-family lemma.',
      'After this condition is proved, attack the next sibling square-residue successor condition.',
      'Do not treat this sub-obligation as a full split proof until all sibling vertex conditions and edge obstructions are handled.',
    ],
  };
}

function buildP848SplitAtomSuccessorPackets(problem, packets) {
  const parentPackets = packets.filter((packet) => (
    packet.priority === 'highest_singleton_profile'
    || (Number(packet.prime) === 13 && packet.priority === 'high_p13_active_lane')
  ));
  const successors = [];
  for (const parentPacket of parentPackets) {
    const conditions = parentPacket.vertexPresenceRefinement?.conditions ?? [];
    for (const [index, condition] of conditions.entries()) {
      successors.push(buildP848SplitAtomSuccessorPacket(problem, parentPacket, condition, index + 1));
    }
  }
  return successors;
}

