  lines.push(`- Status: \`${packet.edgeCongruencePersistence?.status ?? '(none)'}\``);
  lines.push(`- Proof kind: \`${packet.edgeCongruencePersistence?.proofKind ?? '(none)'}\``);
  lines.push(`- Edge atoms: \`${packet.edgeCongruencePersistence?.edgeAtomCount ?? 0}\``);
  lines.push(`- Verified edge atoms: \`${packet.edgeCongruencePersistence?.verifiedEdgeAtomCount ?? 0}\``);
  lines.push(`- Failed edge atoms: \`${packet.edgeCongruencePersistence?.failedEdgeAtomCount ?? 0}\``);
