export function refreshProblemTaskList(problem) {
  const formalizationWorkRefresh = refreshProblemFormalizationWork(problem);
  if (!formalizationWorkRefresh.ok) {
    return {
      ok: false,
      problemId: problem.problemId,
      error: formalizationWorkRefresh.error ?? 'Failed to refresh formalization-work prerequisite for task list.',
      formalizationWorkRefresh,
      taskList: null,
      jsonPath: null,
      markdownPath: null,
    };
  }

  let taskList = buildProblemTaskList(problem);
  const splitAtomPacketWrite = writeP848SplitAtomPacketsFromTaskList(problem, taskList);
  if (splitAtomPacketWrite?.ok) {
    taskList = buildProblemTaskList(problem);
  }
  const paths = getProblemTaskListPaths(problem);
  ensureDir(paths.packProblemDir);
  writeJson(paths.taskListJsonPath, taskList);
  writeText(paths.taskListMarkdownPath, renderProblemTaskListMarkdown(taskList));

  return {
    ok: true,
    problemId: problem.problemId,
    taskList,
    jsonPath: paths.taskListJsonPath,
    markdownPath: paths.taskListMarkdownPath,
    formalizationWorkRefresh,
    splitAtomPacketWrite,
  };
}

function buildTaskLoopFingerprint(taskList) {
  return JSON.stringify({
    activeRoute: taskList.currentState?.activeRoute ?? null,
    currentClaimSurface: taskList.currentState?.currentClaimSurface ?? null,
    nextHonestMove: taskList.currentState?.nextHonestMove ?? null,
    latestVerifiedInterval: taskList.currentState?.latestVerifiedInterval ?? null,
    currentObjective: {
      formalizationId: taskList.currentObjective?.formalizationId ?? null,
      focusId: taskList.currentObjective?.focusId ?? null,
      activeWorkId: taskList.currentObjective?.activeWorkId ?? null,
      activeWorkStatus: taskList.currentObjective?.activeWorkStatus ?? null,
    },
    currentTasks: (taskList.currentTasks ?? []).slice(0, 8).map((task) => ({
      taskId: task.taskId,
      status: task.status,
      title: task.title,
      task: task.task,
    })),
    nextNeededSteps: (taskList.nextNeededSteps ?? []).slice(0, 8).map((step) => ({
      stepId: step.stepId,
      status: step.status,
      task: step.task,
      source: step.source,
    })),
  });
}

function pickHighestValueLoopStep(taskList) {
  const recommended = (taskList.nextNeededSteps ?? []).find((step) => step.status === 'next' || step.status === 'high');
  if (recommended) {
    return {
      source: recommended.source ?? 'next_needed_steps',
      stepId: recommended.stepId,
      task: recommended.task,
      command: recommended.command ?? null,
    };
  }

  const remainingGap = (taskList.currentTasks ?? []).find((task) => task.taskId === 'discharge_first_remaining_gap');
  if (remainingGap) {
    return {
      source: 'current_tasks',
      stepId: remainingGap.taskId,
      task: remainingGap.task,
      command: remainingGap.command ?? null,
    };
  }

  const currentWork = (taskList.currentTasks ?? []).find((task) => task.taskId === 'execute_current_work_packet');
  if (currentWork) {
    return {
      source: 'current_tasks',
      stepId: currentWork.taskId,
      task: currentWork.task,
      command: currentWork.command ?? null,
    };
  }

  return null;
}

function renderProblemTaskLoopRunMarkdown(run) {
  const lines = [
    `# ${run.displayName} Task Loop Run`,
    '',
    `- Problem id: \`${run.problemId}\``,
    `- Requested passes: \`${run.requestedPasses}\``,
    `- Executed passes: \`${run.executedPasses}\``,
    `- Stop reason: \`${run.stopReason}\``,
    `- Converged: \`${run.converged ? 'yes' : 'no'}\``,
  ];

  if (run.convergedAtPass) {
    lines.push(`- Converged at pass: \`${run.convergedAtPass}\``);
  }

  if (run.currentState) {
    lines.push(`- Active route: \`${run.currentState.activeRoute ?? '(none)'}\``);
    lines.push(`- Current claim surface: \`${run.currentState.currentClaimSurface ?? '(none)'}\``);
    lines.push(`- Latest verified interval: ${run.currentState.latestVerifiedInterval ? `\`${run.currentState.latestVerifiedInterval}\`` : '`(none)`'}`);
  }

  if (run.highestValueStep) {
    lines.push(`- Highest-value next step: \`${run.highestValueStep.stepId ?? '(none)'}\` | ${run.highestValueStep.task ?? '(none)'}`);
    if (run.highestValueStep.command) {
      lines.push(`- Highest-value command: \`${run.highestValueStep.command}\``);
    }
  }

  lines.push('', '## Passes', '');
  for (const pass of run.passes ?? []) {
    lines.push(`- Pass ${pass.passNumber}: changed=\`${pass.changed ? 'yes' : 'no'}\` | active work=\`${pass.activeWorkId ?? '(none)'}\` | next=\`${pass.highestValueStep?.stepId ?? '(none)'}\`${pass.highestValueStep?.task ? ` | ${pass.highestValueStep.task}` : ''}`);
  }

  lines.push('');
  return lines.join('\n');
}

export function runProblemTaskListLoop(problem, options = {}) {
  const requestedPassesRaw = Number.parseInt(String(options.passes ?? 1), 10);
  const requestedPasses = Number.isFinite(requestedPassesRaw) && requestedPassesRaw > 0 ? requestedPassesRaw : 1;
  const stopOnConvergence = options.stopOnConvergence !== false;
  const paths = getProblemTaskLoopRunPaths(problem);
  const passes = [];
  let previousFingerprint = null;
  let finalTaskList = null;
  let converged = false;
  let convergedAtPass = null;

  for (let passNumber = 1; passNumber <= requestedPasses; passNumber += 1) {
    const refresh = refreshProblemTaskList(problem);
    if (!refresh.ok) {
      return {
        ok: false,
        problemId: problem.problemId,
        requestedPasses,
        executedPasses: passes.length,
        stopReason: 'refresh_failed',
        error: refresh.error ?? 'Failed to refresh canonical task-list surfaces during loop run.',
        passes,
        jsonPath: null,
        markdownPath: null,
      };
    }

    finalTaskList = refresh.taskList;
    const fingerprint = buildTaskLoopFingerprint(finalTaskList);
    const changed = fingerprint !== previousFingerprint;
    const highestValueStep = pickHighestValueLoopStep(finalTaskList);

    passes.push({
      passNumber,
      changed,
      activeRoute: finalTaskList.currentState?.activeRoute ?? null,
      latestVerifiedInterval: finalTaskList.currentState?.latestVerifiedInterval ?? null,
      currentClaimSurface: finalTaskList.currentState?.currentClaimSurface ?? null,
      formalizationId: finalTaskList.currentObjective?.formalizationId ?? null,
      focusId: finalTaskList.currentObjective?.focusId ?? null,
      activeWorkId: finalTaskList.currentObjective?.activeWorkId ?? null,
      activeWorkStatus: finalTaskList.currentObjective?.activeWorkStatus ?? null,
      highestValueStep,
      fingerprint,
    });

    if (!changed) {
      converged = true;
      if (convergedAtPass === null) {
        convergedAtPass = passNumber;
      }
      if (stopOnConvergence) {
        break;
      }
    }

    previousFingerprint = fingerprint;
  }

  const executedPasses = passes.length;
  const stopReason = converged && stopOnConvergence
    ? 'converged'
    : executedPasses >= requestedPasses
      ? 'requested_pass_limit_reached'
      : 'completed';
  const highestValueStep = finalTaskList ? pickHighestValueLoopStep(finalTaskList) : null;
  const result = {
    ok: true,
    schema: 'erdos.problem_task_loop_run/1',
    generatedAt: new Date().toISOString(),
    problemId: problem.problemId,
    displayName: problem.displayName,
    title: problem.title,
    requestedPasses,
    executedPasses,
    stopOnConvergence,
    stopReason,
    converged,
    convergedAtPass,
    currentState: finalTaskList?.currentState ?? null,
    currentObjective: finalTaskList?.currentObjective ?? null,
    highestValueStep,
    passes,
    commands: {
      taskList: `erdos problem task-list ${problem.problemId}`,
      taskListRefresh: `erdos problem task-list-refresh ${problem.problemId}`,
      rerun: `erdos problem task-list-run ${problem.problemId} --passes ${requestedPasses}`,
    },
    sources: {
      taskListJsonPath: finalTaskList?.sources?.taskListJsonPath ?? null,
      taskListMarkdownPath: finalTaskList?.sources?.taskListMarkdownPath ?? null,
      taskLoopRunJsonPath: paths.taskLoopRunJsonPath,
      taskLoopRunMarkdownPath: paths.taskLoopRunMarkdownPath,
    },
  };

  ensureDir(paths.packProblemDir);
  writeJson(paths.taskLoopRunJsonPath, result);
  writeText(paths.taskLoopRunMarkdownPath, renderProblemTaskLoopRunMarkdown(result));

  return {
    ...result,
    jsonPath: paths.taskLoopRunJsonPath,
    markdownPath: paths.taskLoopRunMarkdownPath,
  };
}
